from collections import deque
from typing import Optional

def max_depth(root: Optional['TreeNode']) -> int:
    if root is None:
        return 0
    queue: deque = deque([root])
    depth = 0
    while queue:
        for _ in range(len(queue)):
            node = queue.popleft()
            if node.left:
                queue.append(node.left)
            if node.right:
                queue.append(node.right)
        depth += 1
    return depth

